// C program to check if the linked list is circular
#include <stdio.h>
#include <stdlib.h>
struct Node {
    int data;
    struct Node* next;
};
int isCircular(struct Node* head)
{

    // If given linked list is null then it is circular
    if (head == NULL) {
        return 1;
    }
    struct Node* ptr;
    ptr = head->next;

    // Traversing linked list till last node
    while (ptr != NULL && ptr != head) {
        ptr = ptr->next;
    }

    // will return 1 if Linked list is circular else 0
    return (ptr == head);
}

struct Node* newnode(int data)
{
    struct Node* first;
    first = (struct Node*)malloc(sizeof(struct Node));
    first->data = data;
    first->next = NULL;
    return first;
}

int main()
{

    struct Node* head = newnode(10);
    head->next = newnode(12);
    head->next->next = newnode(14);
    head->next->next->next = newnode(16);
    head->next->next->next->next = head;

    // if it will be 1 then it means linked list is
    // circular 
    if (isCircular(head)) {
        printf("Linked List is Circular\n");
    }
    else {
        printf("Linked List is Not Circular\n");
    }

    return 0;
}

// C program to merge two sorted
// linked lists
#include <assert.h>
#include <stdio.h>
#include <stdlib.h>

// Linked List Node
struct Node {
    int data;
    struct Node* next;
};

/* Pull off the front node of the
   source and put it in dest
 */
void MoveNode(struct Node** destRef,
              struct Node** sourceRef);

/* Takes two lists sorted in increasing order,
   and splices their nodes together to make
   one big sorted list which is returned.  */
struct Node* SortedMerge(struct Node* a, struct Node* b)
{
    /* A dummy first node to hang the
       result on */
    struct Node dummy;

    /* tail points to the last result node  */
    struct Node* tail = &dummy;

    /* so tail->next is the place to add new
       nodes to the result. */
    dummy.next = NULL;
    while (1) {
        if (a == NULL) {
            /* if either list runs out, use the
               other list */
            tail->next = b;
            break;
        }
        else if (b == NULL) {
            tail->next = a;
            break;
        }
        if (a->data <= b->data)
            MoveNode(&(tail->next), &a);
        else
            MoveNode(&(tail->next), &b);
        tail = tail->next;
    }
    return (dummy.next);
}

/* UTILITY FUNCTIONS */
/* MoveNode() function takes the node
   from the front of the source, and
   move it to the front of the dest.
   It is an error to call this with the
   source list empty.

   Before calling MoveNode():
   source == {1, 2, 3}
   dest == {1, 2, 3}

   After calling MoveNode():
   source == {2, 3}
   dest == {1, 1, 2, 3} */
void MoveNode(struct Node** destRef,
              struct Node** sourceRef)
{
    /* The front source node  */
    struct Node* newNode = *sourceRef;
    assert(newNode != NULL);

    /* Advance the source pointer */
    *sourceRef = newNode->next;

    /* Link the old dest off the new node */
    newNode->next = *destRef;

    /* Move dest to point to the new node */
    *destRef = newNode;
}

/* Function to insert a node at the beginning of the
   linked list */
void push(struct Node** head_ref, int new_data)
{
    /* allocate node */
    struct Node* new_node
        = (struct Node*)malloc(sizeof(struct Node));

    /* put in the data  */
    new_node->data = new_data;

    /* link the old list off the new node */
    new_node->next = (*head_ref);

    /* move the head to point to the new node */
    (*head_ref) = new_node;
}

/* Function to print nodes in a given linked list */
void printList(struct Node* node)
{
    while (node != NULL) {
        printf("%d ", node->data);
        node = node->next;
    }
}

/* Driver program to test above functions*/
int main()
{
    /* Start with the empty list */
    struct Node* res = NULL;
    struct Node* a = NULL;
    struct Node* b = NULL;

    /* Let us create two sorted linked lists to test
      the functions
       Created lists, a: 5->10->15,  b: 2->3->20 */
    push(&a, 15);
    push(&a, 10);
    push(&a, 5);

    push(&b, 20);
    push(&b, 3);
    push(&b, 2);

    /* Remove duplicates from linked list */
    res = SortedMerge(a, b);

    printf("Merged Linked List is: \n");
    printList(res);

    return 0;
}
